/**
 * Generate Gemini firewall config.
 *
 * Data source: https://ai.google.dev/api
 *
 * Gemini (Google AI Studio) uses API key authentication via the
 * `x-goog-api-key` header (preferred over the `?key=` query parameter).
 * Token format: AIza + 35 chars (39 total).
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://ai.google.dev/api";
// Format: AIza + [A-Za-z0-9_-]{35} (total 39 chars)
const PLACEHOLDER_VALUE = "AIzaCoffeeSafeLocalCoffeeSafeLocalCoffe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Gemini API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:gemini",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const geminiFirewall = {",
    '  name: "gemini",',
    '  description: "Google Gemini API",',
    "  placeholders: {",
    `    GEMINI_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://generativelanguage.googleapis.com",',
    "      auth: {",
    "        headers: {",
    '          "x-goog-api-key": "${{ secrets.GEMINI_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Gemini firewall config...");
  const ts = generateTypeScript();
  writeOutput("gemini", ts, import.meta.dirname);
}
